python3 -c "
import openpyxl
from collections import Counter

wb = openpyxl.load_workbook('/Users/royrigamonti/chuck/genova/sped.xlsx', read_only=True)
ws = wb['Sheet1']

headers = None
col_idx = {}

# Look at MAWB rows to understand structure
mawb_rows = []
hawb_sample = []

for i, row in enumerate(ws.iter_rows(values_only=True)):
    if i == 0:
        headers = row
        col_idx = {h: j for j, h in enumerate(headers)}
        continue
    pratica = str(row[col_idx['Tipo Pratica']]).strip()
    if pratica == 'MAWB' and len(mawb_rows) < 5:
        mawb_rows.append(row)
    if pratica == 'HAWB' and len(hawb_sample) < 3:
        hawb_sample.append(row)

print('=== SAMPLE MAWB ROWS ===')
important_cols = ['Spedizione Raggruppata', 'Spedizione', 'Tipo Pratica', 'Servizio', 'Corrispondente', 
                  'Nazione', 'Nazione Mittente', 'Nazione Destinatario', 'Zona Partenza', 'Zona Arrivo',
                  'BU Caratteristica', 'BU Attributo', 'Committente']
for row in mawb_rows:
    print('---')
    for col in important_cols:
        if col in col_idx:
            val = str(row[col_idx[col]]).strip()
            if val and val != '-' and val != 'None':
                print(f'  {col}: {val}')

print()
print('=== SAMPLE HAWB ROWS ===')
for row in hawb_sample:
    print('---')
    for col in important_cols:
        if col in col_idx:
            val = str(row[col_idx[col]]).strip()
            if val and val != '-' and val != 'None':
                print(f'  {col}: {val}')
"

